{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "lean-stack-bootstrapper-blueprint-output",
  "required": [
    "services",
    "monthly_ceiling_usd",
    "alert_threshold_pct",
    "upgrade_triggers",
    "vendor_lock_acceptance",
    "forbidden_seen"
  ],
  "properties": {
    "services": {
      "description": "\u22645 services with role assignment."
    },
    "monthly_ceiling_usd": {
      "description": "Hard cap."
    },
    "alert_threshold_pct": {
      "description": "Default 80."
    },
    "upgrade_triggers": {
      "description": "{metric, threshold, action} per trigger."
    },
    "vendor_lock_acceptance": {
      "description": "True iff portability is explicitly deferred."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
